# solution.py
"""CodeSquad / Team Collaboration backend.

A self-contained, thread-safe, in-memory collaboration engine that powers a
web-based system for shared code review, debugging, task tracking and team
communication.

The public surface is :class:`TeamCollaborationManager`, which composes a set
of cooperating sub-stores (users, projects, tasks, messages, performance,
reports).  Every sub-store shares a single re-entrant lock so that compound,
cross-domain operations stay consistent under concurrent access while still
supporting many simultaneous sessions.

Only the Python standard library is used.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple

__all__ = [
    "TeamCollaborationManager",
    "CodeSquad",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task / review item."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Role-based access levels for users."""

    ADMIN = "admin"
    MEMBER = "member"
    VIEWER = "viewer"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Logical report categories."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the collaboration engine."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    content: bytes = b""


@dataclass
class User:
    """A registered user of the system."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project / workspace that groups tasks and conversations."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work (review, bug, feature) inside a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A chat / annotation message attached to a project or task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """Peer feedback / rating for a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return a deep copy so callers can never mutate stored state."""

    return copy.deepcopy(obj)


def _clone_list(items):
    return [copy.deepcopy(item) for item in items]


def _is_valid_email(email) -> bool:
    if not isinstance(email, str):
        return False
    email = email.strip()
    if not email:
        return False
    return "@" in email


def _completion_rate(tasks: List[Task]) -> float:
    if not tasks:
        return 0.0
    completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
    return completed / len(tasks)


def _average_completion_time(tasks: List[Task]) -> Optional[float]:
    durations = []
    for t in tasks:
        if (
            t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ):
            durations.append((t.completed_at - t.started_at).total_seconds())
    if not durations:
        return None
    return sum(durations) / len(durations)


# ---------------------------------------------------------------------------
# Shared state
# ---------------------------------------------------------------------------
class _State:
    """Central, lock-guarded data store shared by every sub-component."""

    def __init__(self, now: Callable[[], datetime]):
        self.lock = threading.RLock()
        self._now = now
        self._next_id = 1
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

    # -- time / id ---------------------------------------------------------
    def now(self) -> datetime:
        return self._now()

    def next_id(self) -> int:
        nid = self._next_id
        self._next_id += 1
        return nid

    # -- lookups (assume lock already held) --------------------------------
    def require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    # -- derived collections ----------------------------------------------
    def tasks_for_project(self, project_id: int) -> List[Task]:
        return sorted(
            (t for t in self.tasks.values() if t.project_id == project_id),
            key=lambda t: t.id,
        )

    def tasks_for_assignee(self, user_id: int) -> List[Task]:
        return sorted(
            (t for t in self.tasks.values() if t.assignee_id == user_id),
            key=lambda t: t.id,
        )

    def ratings_for_user(self, user_id: int) -> List[Rating]:
        return sorted(
            (r for r in self.ratings.values() if r.ratee_id == user_id),
            key=lambda r: r.id,
        )


class _Component:
    """Base class for every sub-store; exposes the shared lock."""

    def __init__(self, state: _State):
        self._state = state
        self._lock = state.lock


# ---------------------------------------------------------------------------
# User store
# ---------------------------------------------------------------------------
class UserStore(_Component):
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("Username must be a non-empty string")
            if not _is_valid_email(email):
                raise ValidationError("Email must be a valid address")
            if not isinstance(role, UserRole):
                raise ValidationError("Role must be a UserRole")
            if self._username_taken(username):
                raise DuplicateError(
                    "Username {0!r} already exists".format(username)
                )
            if self._email_taken(email):
                raise DuplicateError("Email {0!r} already exists".format(email))

            user = User(
                id=self._state.next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._state.now(),
            )
            self._state.users[user.id] = user
            return _clone(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return _clone(self._state.require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self._state.users.values(), key=lambda u: u.id)
            return _clone_list(users)

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._state.require_user(user_id)
            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("Username must be a non-empty string")
                if self._username_taken(username, exclude_id=user_id):
                    raise DuplicateError(
                        "Username {0!r} already exists".format(username)
                    )
            if email is not None:
                if not _is_valid_email(email):
                    raise ValidationError("Email must be a valid address")
                if self._email_taken(email, exclude_id=user_id):
                    raise DuplicateError(
                        "Email {0!r} already exists".format(email)
                    )
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("Role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            self._state.require_user(user_id)
            for project in self._state.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "User {0} owns a project".format(user_id)
                    )
            for task in self._state.tasks.values():
                if (
                    task.assignee_id == user_id
                    and task.status != TaskStatus.COMPLETED
                ):
                    raise ConflictError(
                        "User {0} has an open task".format(user_id)
                    )
            del self._state.users[user_id]

    # -- internals ---------------------------------------------------------
    def _username_taken(self, username, exclude_id=None) -> bool:
        for user in self._state.users.values():
            if user.id == exclude_id:
                continue
            if user.username == username:
                return True
        return False

    def _email_taken(self, email, exclude_id=None) -> bool:
        for user in self._state.users.values():
            if user.id == exclude_id:
                continue
            if user.email == email:
                return True
        return False


# ---------------------------------------------------------------------------
# Project store
# ---------------------------------------------------------------------------
class ProjectStore(_Component):
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            self._state.require_user(owner_id)
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("Project name must be a non-empty string")
            if end_date < start_date:
                raise ValidationError("End date cannot precede start date")

            project = Project(
                id=self._state.next_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description or "",
                created_at=self._state.now(),
            )
            self._state.projects[project.id] = project
            return _clone(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return _clone(self._state.require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(
                self._state.projects.values(), key=lambda p: p.id
            )
            return _clone_list(projects)

    def update_project(
        self,
        project_id,
        name=None,
        description=None,
        start_date=None,
        end_date=None,
    ) -> Project:
        with self._lock:
            project = self._state.require_project(project_id)
            new_name = project.name if name is None else name
            new_desc = project.description if description is None else description
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date

            if not isinstance(new_name, str) or not new_name.strip():
                raise ValidationError("Project name must be a non-empty string")
            if new_end < new_start:
                raise ValidationError("End date cannot precede start date")

            project.name = new_name
            project.description = new_desc
            project.start_date = new_start
            project.end_date = new_end
            return _clone(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._state.require_project(project_id)
            task_ids = [
                t.id
                for t in self._state.tasks.values()
                if t.project_id == project_id
            ]
            # Cascade: remove messages tied to the project or to its tasks.
            message_ids = [
                m.id
                for m in self._state.messages.values()
                if m.project_id == project_id or m.task_id in task_ids
            ]
            for mid in message_ids:
                del self._state.messages[mid]
            for tid in task_ids:
                del self._state.tasks[tid]
            del self._state.projects[project_id]


# ---------------------------------------------------------------------------
# Task store
# ---------------------------------------------------------------------------
class TaskStore(_Component):
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None, description=""
    ) -> Task:
        with self._lock:
            project = self._state.require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("Task title must be a non-empty string")
            if assignee_id is not None:
                self._state.require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError(
                    "Deadline cannot precede the project start date"
                )

            task = Task(
                id=self._state.next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                description=description or "",
                created_at=self._state.now(),
            )
            self._state.tasks[task.id] = task
            return _clone(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return _clone(self._state.require_task(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            self._state.require_project(project_id)
            return _clone_list(self._state.tasks_for_project(project_id))

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            self._state.require_user(user_id)
            return _clone_list(self._state.tasks_for_assignee(user_id))

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            self._state.require_user(assignee_id)
            task.assignee_id = assignee_id
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            if deadline is not None:
                project = self._state.require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError(
                        "Deadline cannot precede the project start date"
                    )
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._state.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("Status must be a TaskStatus")
            now = self._state.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return _clone(task)


# ---------------------------------------------------------------------------
# Message store
# ---------------------------------------------------------------------------
class MessageStore(_Component):
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._state.require_user(author_id)
            if project_id is None and task_id is None:
                raise ValidationError(
                    "A message must target a project or a task"
                )
            if project_id is not None and task_id is not None:
                raise ValidationError(
                    "A message cannot target both a project and a task"
                )
            if project_id is not None:
                self._state.require_project(project_id)
            if task_id is not None:
                self._state.require_task(task_id)
            if parent_id is not None:
                self._state.require_message(parent_id)

            attachment_specs = list(attachments) if attachments else []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError(
                    "A message must have a body or at least one attachment"
                )

            now = self._state.now()
            built = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._state.next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
            )
            self._state.messages[message.id] = message
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError(
                    "Only the author may edit this message"
                )
            if not isinstance(new_body, str) or not new_body.strip():
                raise ValidationError("Message body must be a non-empty string")
            message.body = new_body
            message.edited_at = self._state.now()
            return _clone(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "Only the author may attach to this message"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("Filename must be a non-empty string")
            attachment = self._build_attachment(
                filename, data, user_id, self._state.now()
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            self._state.require_project(project_id)
            messages = sorted(
                (
                    m
                    for m in self._state.messages.values()
                    if m.project_id == project_id
                ),
                key=lambda m: m.id,
            )
            return _clone_list(messages)

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            self._state.require_task(task_id)
            messages = sorted(
                (
                    m
                    for m in self._state.messages.values()
                    if m.task_id == task_id
                ),
                key=lambda m: m.id,
            )
            return _clone_list(messages)

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._state.require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "Only the author may delete this message"
                )
            del self._state.messages[message_id]

    # -- internals ---------------------------------------------------------
    @staticmethod
    def _build_attachment(filename, data, user_id, when) -> Attachment:
        payload = data if data is not None else b""
        if isinstance(payload, str):
            payload = payload.encode("utf-8")
        return Attachment(
            filename=filename,
            size=len(payload),
            uploaded_by=user_id,
            uploaded_at=when,
            content=bytes(payload),
        )


# ---------------------------------------------------------------------------
# Performance dashboard
# ---------------------------------------------------------------------------
class PerformanceService(_Component):
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._state.require_user(user_id)
            return _completion_rate(self._state.tasks_for_assignee(user_id))

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._state.require_user(user_id)
            return _average_completion_time(
                self._state.tasks_for_assignee(user_id)
            )

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        with self._lock:
            self._state.require_user(rater_id)
            self._state.require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("Users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("Score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("Score must be between 1 and 5")
            if task_id is not None:
                self._state.require_task(task_id)

            rating = Rating(
                id=self._state.next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._state.now(),
            )
            self._state.ratings[rating.id] = rating
            return _clone(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._state.require_user(user_id)
            ratings = self._state.ratings_for_user(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": _clone_list(ratings),
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._state.require_user(user_id)
            tasks = self._state.tasks_for_assignee(user_id)
            ratings = self._state.ratings_for_user(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": _completion_rate(tasks),
                "average_completion_time": _average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ---------------------------------------------------------------------------
# Reporting
# ---------------------------------------------------------------------------
class ReportService(_Component):
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            project = self._state.require_project(project_id)
            tasks = self._state.tasks_for_project(project_id)
            now = self._state.now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, Dict[str, object]] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1

            for bucket in per_assignee.values():
                total = bucket["total_tasks"]
                bucket["completion_rate"] = (
                    bucket["completed_tasks"] / total if total else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": len(tasks),
                "status_counts": status_counts,
                "completion_rate": _completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
                "generated_at": now,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._state.require_project(project_id)
                scoped_tasks = self._state.tasks_for_project(project_id)
                scope = "project"
            else:
                scoped_tasks = sorted(
                    self._state.tasks.values(), key=lambda t: t.id
                )
                scope = "global"

            assignee_ids = sorted(
                {
                    t.assignee_id
                    for t in scoped_tasks
                    if t.assignee_id is not None
                }
            )
            rows = []
            for uid in assignee_ids:
                user = self._state.users.get(uid)
                user_tasks = [t for t in scoped_tasks if t.assignee_id == uid]
                ratings = self._state.ratings_for_user(uid)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                rows.append(
                    {
                        "user_id": uid,
                        "username": user.username if user else "",
                        "total_tasks": len(user_tasks),
                        "completed_tasks": sum(
                            1
                            for t in user_tasks
                            if t.status == TaskStatus.COMPLETED
                        ),
                        "completion_rate": _completion_rate(user_tasks),
                        "average_completion_time": _average_completion_time(
                            user_tasks
                        ),
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope": scope,
                "project_id": project_id,
                "rows": rows,
                "generated_at": self._state.now(),
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            user = self._state.require_user(user_id)
            tasks = self._state.tasks_for_assignee(user_id)
            ratings = self._state.ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": _completion_rate(tasks),
                "average_completion_time": _average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
                "generated_at": self._state.now(),
            }

    # -- export ------------------------------------------------------------
    def export_report(self, report, report_format) -> object:
        if not isinstance(report, dict):
            raise ValidationError("Report must be a dictionary")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("Format must be a ReportFormat")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    @staticmethod
    def _cell(value):
        if value is None:
            return ""
        if isinstance(value, datetime):
            return value.isoformat()
        if isinstance(value, Enum):
            return value.value
        return value

    def _to_csv(self, report) -> str:
        output = io.StringIO()
        writer = csv.writer(output)
        cell = self._cell

        if isinstance(report.get("rows"), list):
            rows = report["rows"]
            if rows:
                headers = list(rows[0].keys())
            else:
                headers = [
                    "user_id",
                    "username",
                    "total_tasks",
                    "completed_tasks",
                    "completion_rate",
                    "average_completion_time",
                    "rating_count",
                    "rating_average",
                ]
            writer.writerow(headers)
            for row in rows:
                writer.writerow([cell(row.get(h)) for h in headers])
        elif isinstance(report.get("tasks"), list):
            scalars = [
                (k, v)
                for k, v in report.items()
                if not isinstance(v, (list, dict))
            ]
            writer.writerow([k for k, _ in scalars])
            writer.writerow([cell(v) for _, v in scalars])
            tasks = report["tasks"]
            if tasks:
                writer.writerow([])
                theaders = list(tasks[0].keys())
                writer.writerow(theaders)
                for task in tasks:
                    writer.writerow([cell(task.get(h)) for h in theaders])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        writer.writerow(
                            [
                                "{0}.{1}".format(key, sub_key),
                                cell(sub_value),
                            ]
                        )
                elif isinstance(value, list):
                    writer.writerow([key, "{0} items".format(len(value))])
                else:
                    writer.writerow([key, cell(value)])
        return output.getvalue()

    def _to_pdf(self, report) -> bytes:
        return _render_pdf(_report_to_lines(report))


# ---------------------------------------------------------------------------
# PDF rendering (minimal, dependency-free)
# ---------------------------------------------------------------------------
def _report_to_lines(report: dict) -> List[str]:
    lines = ["Report: {0}".format(report.get("report_type", "report"))]
    for key, value in report.items():
        if key == "report_type":
            continue
        if isinstance(value, dict):
            lines.append("{0}:".format(key))
            for sub_key, sub_value in value.items():
                lines.append("  {0}: {1}".format(sub_key, sub_value))
        elif isinstance(value, list):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _pdf_escape(text: str) -> str:
    return (
        str(text)
        .replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
    )


def _render_pdf(lines: List[str]) -> bytes:
    if not lines:
        lines = [""]

    stream_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(lines):
        escaped = _pdf_escape(line)
        if index == 0:
            stream_parts.append("({0}) Tj".format(escaped))
        else:
            stream_parts.append("T*")
            stream_parts.append("({0}) Tj".format(escaped))
    stream_parts.append("ET")
    stream = "\n".join(stream_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        ),
        b"<< /Length "
        + str(len(stream)).encode("ascii")
        + b" >>\nstream\n"
        + stream
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(number).encode("ascii")
        out += body
        out += b"\nendobj\n"

    xref_offset = len(out)
    count = len(objects)
    out += "xref\n0 {0}\n".format(count + 1).encode("ascii")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    out += "trailer\n<< /Size {0} /Root 1 0 R >>\n".format(
        count + 1
    ).encode("ascii")
    out += b"startxref\n"
    out += "{0}\n".format(xref_offset).encode("ascii")
    out += b"%%EOF"
    return bytes(out)


# ---------------------------------------------------------------------------
# Facade manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Single entry point that wires the sub-stores together.

    All sub-stores share one re-entrant lock (exposed as ``_lock`` on each),
    guaranteeing consistency for compound, cross-domain operations while
    allowing many concurrent collaboration sessions.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        state = _State(now if now is not None else datetime.now)
        self._state = state
        self._lock = state.lock
        self.users = UserStore(state)
        self.projects = ProjectStore(state)
        self.tasks = TaskStore(state)
        self.messages = MessageStore(state)
        self.performance = PerformanceService(state)
        self.reports = ReportService(state)

    # -- users -------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        return self.users.register_user(username, email, role)

    def get_user(self, user_id) -> User:
        return self.users.get_user(user_id)

    def list_users(self) -> List[User]:
        return self.users.list_users()

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        return self.users.update_user(user_id, username, email, role)

    def delete_user(self, user_id) -> None:
        return self.users.delete_user(user_id)

    # -- projects ----------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        return self.projects.create_project(
            name, start_date, end_date, owner_id, description
        )

    def get_project(self, project_id) -> Project:
        return self.projects.get_project(project_id)

    def list_projects(self) -> List[Project]:
        return self.projects.list_projects()

    def update_project(
        self,
        project_id,
        name=None,
        description=None,
        start_date=None,
        end_date=None,
    ) -> Project:
        return self.projects.update_project(
            project_id, name, description, start_date, end_date
        )

    def delete_project(self, project_id) -> None:
        return self.projects.delete_project(project_id)

    # -- tasks -------------------------------------------------------------
    def create_task(
        self, project_id, title, assignee_id=None, deadline=None, description=""
    ) -> Task:
        return self.tasks.create_task(
            project_id, title, assignee_id, deadline, description
        )

    def get_task(self, task_id) -> Task:
        return self.tasks.get_task(task_id)

    def list_tasks_by_project(self, project_id) -> List[Task]:
        return self.tasks.list_tasks_by_project(project_id)

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        return self.tasks.list_tasks_by_assignee(user_id)

    def assign_task(self, task_id, assignee_id) -> Task:
        return self.tasks.assign_task(task_id, assignee_id)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        return self.tasks.reassign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id) -> Task:
        return self.tasks.unassign_task(task_id)

    def set_deadline(self, task_id, deadline) -> Task:
        return self.tasks.set_deadline(task_id, deadline)

    def update_status(self, task_id, status) -> Task:
        return self.tasks.update_status(task_id, status)

    # -- messages ----------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        return self.messages.post_message(
            author_id, body, project_id, task_id, parent_id, attachments
        )

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        return self.messages.edit_message(message_id, editor_id, new_body)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        return self.messages.add_attachment(message_id, user_id, filename, data)

    def list_messages_by_project(self, project_id) -> List[Message]:
        return self.messages.list_messages_by_project(project_id)

    def list_messages_by_task(self, task_id) -> List[Message]:
        return self.messages.list_messages_by_task(task_id)

    def delete_message(self, message_id, user_id) -> None:
        return self.messages.delete_message(message_id, user_id)

    # -- performance -------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        return self.performance.get_completion_rate(user_id)

    def get_average_completion_time(self, user_id) -> Optional[float]:
        return self.performance.get_average_completion_time(user_id)

    def submit_rating(
        self, rater_id, ratee_id, score, feedback="", task_id=None
    ) -> Rating:
        return self.performance.submit_rating(
            rater_id, ratee_id, score, feedback, task_id
        )

    def get_ratings_summary(self, user_id) -> dict:
        return self.performance.get_ratings_summary(user_id)

